update health_event
event_type = #{eventType}, content = #{content}, event_time = #{eventTime}, is_public = #{isPublic}, updated_time = #{updatedTime},
where user_id = #{userId} and id = #{id}

mapper.select:
select * from health_event


        event_type = #{eventType}


        and event_time between #{eventTimeBegan} and #{eventTimeEnd}


        and is_public = #{isPublic}

         and user_id = #{userId}

order by created_time desc

select event_type,count(*) num
from health_event
where user_id = #{userId}
    and event_time between #{startTime} and #{endTime}
group by event_type order by num

select * from health_event


        name like concat ('%', #{name}, '%')


        and event_type = #{eventType}


        and event_time between #{eventTimeBegan} and #{eventTimeEnd}


    and is_public = 1

order by created_time desc
